import { useEffect, useState } from 'react';
import api from '../../services/api';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { 
  FiPackage, FiShoppingCart, FiTrendingUp, FiAlertTriangle, 
  FiArrowRight, FiDollarSign, FiUsers, FiTruck,
  FiBarChart2, FiActivity
} from 'react-icons/fi';
import { motion } from 'framer-motion';

export default function Dashboard() {
  const [productosBajoStock, setProductosBajoStock] = useState([]);
  const [ultimasVentas, setUltimasVentas] = useState([]);
  const [stats, setStats] = useState({ totalProductos: 0, ventasHoy: 0, ingresosHoy: 0, totalVentas: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [stockRes, ventasRes, productosRes] = await Promise.all([
          api.get('/reportes/stock-bajo'),
          api.get('/ventas'),
          api.get('/productos')
        ]);
        
        setProductosBajoStock(stockRes.data);
        setUltimasVentas(ventasRes.data.slice(0, 5));
        
        const hoy = new Date().toISOString().split('T')[0];
        const ventasHoy = ventasRes.data.filter(v => v.fecha.split('T')[0] === hoy);
        const ingresosHoy = ventasHoy.reduce((sum, v) => sum + parseFloat(v.total), 0);
        const totalVentas = ventasRes.data.reduce((sum, v) => sum + parseFloat(v.total), 0);
        
        setStats({
          totalProductos: productosRes.data.length,
          ventasHoy: ventasHoy.length,
          ingresosHoy: ingresosHoy,
          totalVentas: totalVentas
        });
      } catch (error) {
        toast.error('Error al cargar datos del dashboard');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex justify-center items-center h-96">
        <div className="relative">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-primary-600"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="h-8 w-8 bg-primary-600 rounded-full animate-pulse"></div>
          </div>
        </div>
      </div>
    );
  }

  const statsCards = [
    { 
      title: 'Productos Activos', 
      value: stats.totalProductos, 
      icon: FiPackage, 
      gradient: 'from-blue-500 to-cyan-500',
      link: '/productos',
      description: 'En inventario'
    },
    { 
      title: 'Ventas Hoy', 
      value: stats.ventasHoy, 
      icon: FiShoppingCart, 
      gradient: 'from-green-500 to-emerald-500',
      link: '/ventas',
      description: 'Transacciones'
    },
    { 
      title: 'Ingresos Hoy', 
      value: `$${stats.ingresosHoy.toFixed(2)}`, 
      icon: FiDollarSign, 
      gradient: 'from-purple-500 to-pink-500',
      link: '/ventas',
      description: 'Total del día'
    },
    { 
      title: 'Ventas Totales', 
      value: `$${stats.totalVentas.toFixed(2)}`, 
      icon: FiTrendingUp, 
      gradient: 'from-orange-500 to-red-500',
      link: '/ventas',
      description: 'Histórico'
    },
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold bg-gradient-to-r from-primary-600 to-purple-600 bg-clip-text text-transparent">
            Panel de Control
          </h1>
          <p className="text-gray-500 mt-1">Bienvenido de vuelta. Aquí está el resumen de tu negocio.</p>
        </div>
        <div className="text-sm text-gray-500 bg-white px-4 py-2 rounded-xl shadow-sm">
          📅 {new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
        </div>
      </div>
      
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {statsCards.map((stat, idx) => {
          const Icon = stat.icon;
          return (
            <motion.div
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx * 0.1 }}
              whileHover={{ scale: 1.05 }}
              className="relative overflow-hidden"
            >
              <Link to={stat.link}>
                <div className={`bg-gradient-to-r ${stat.gradient} p-6 rounded-2xl shadow-lg text-white relative overflow-hidden group`}>
                  <div className="absolute top-0 right-0 -mt-4 -mr-4 w-32 h-32 bg-white/10 rounded-full"></div>
                  <div className="absolute bottom-0 left-0 -mb-4 -ml-4 w-24 h-24 bg-white/10 rounded-full"></div>
                  
                  <div className="relative z-10">
                    <div className="flex items-center justify-between mb-3">
                      <Icon className="text-3xl" />
                      <div className="text-4xl font-bold">{stat.value}</div>
                    </div>
                    <div className="text-sm opacity-90">{stat.title}</div>
                    <div className="text-xs opacity-75 mt-1">{stat.description}</div>
                  </div>
                </div>
              </Link>
            </motion.div>
          );
        })}
      </div>
      
      {/* Two column layout */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Productos con stock bajo */}
        <motion.div
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.3 }}
          className="card-premium overflow-hidden"
        >
          <div className="bg-gradient-to-r from-amber-500 to-orange-500 px-6 py-4">
            <h2 className="text-xl font-semibold text-white flex items-center">
              <FiAlertTriangle className="mr-2" /> Productos con Stock Bajo
            </h2>
          </div>
          <div className="p-6">
            {productosBajoStock.length === 0 ? (
              <div className="text-center py-8">
                <div className="text-5xl mb-3">✅</div>
                <p className="text-gray-500">No hay productos con stock bajo</p>
              </div>
            ) : (
              <ul className="divide-y divide-gray-200">
                {productosBajoStock.map(p => (
                  <li key={p.id} className="py-3 flex justify-between items-center">
                    <div>
                      <p className="font-medium text-gray-800">{p.nombre}</p>
                      <p className="text-xs text-gray-500">Código: {p.codigo}</p>
                    </div>
                    <div className="text-right">
                      <span className="badge-danger">
                        {p.stock_actual} unidades
                      </span>
                      <p className="text-xs text-gray-500 mt-1">Mínimo: {p.stock_minimo}</p>
                    </div>
                  </li>
                ))}
              </ul>
            )}
            <Link to="/productos" className="mt-4 inline-flex items-center text-primary-600 hover:text-primary-700 font-medium">
              Ver todos los productos <FiArrowRight className="ml-1" />
            </Link>
          </div>
        </motion.div>
        
        {/* Últimas ventas */}
        <motion.div
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.4 }}
          className="card-premium overflow-hidden"
        >
          <div className="bg-gradient-to-r from-green-500 to-emerald-500 px-6 py-4">
            <h2 className="text-xl font-semibold text-white flex items-center">
              <FiActivity className="mr-2" /> Últimas Ventas Registradas
            </h2>
          </div>
          <div className="p-6">
            {ultimasVentas.length === 0 ? (
              <div className="text-center py-8">
                <div className="text-5xl mb-3">📊</div>
                <p className="text-gray-500">No hay ventas registradas</p>
              </div>
            ) : (
              <ul className="divide-y divide-gray-200">
                {ultimasVentas.map(v => (
                  <li key={v.id} className="py-3 flex justify-between items-center">
                    <div>
                      <p className="font-medium text-gray-800">{v.cliente_nombre}</p>
                      <p className="text-xs text-gray-500">{new Date(v.fecha).toLocaleString()}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-green-600 font-bold">${parseFloat(v.total).toFixed(2)}</p>
                      <p className="text-xs text-gray-500">ID: #{v.id}</p>
                    </div>
                  </li>
                ))}
              </ul>
            )}
            <Link to="/ventas" className="mt-4 inline-flex items-center text-primary-600 hover:text-primary-700 font-medium">
              Ver historial completo <FiArrowRight className="ml-1" />
            </Link>
          </div>
        </motion.div>
      </div>
    </div>
  );
}
